// ═══════════════════════════════════════════
// NEURAL AI BACKGROUND
// ═══════════════════════════════════════════
function initBg() {
  const W = () => window.innerWidth, H = () => window.innerHeight

  // Grid
  ;(function() {
    const c = document.getElementById('gc'), ctx = c.getContext('2d')
    function resize() { c.width = W(); c.height = H() }
    resize(); window.addEventListener('resize', resize)
    let off = 0
    function draw() {
      ctx.clearRect(0, 0, c.width, c.height)
      const vp = { x: c.width/2, y: c.height*.36 }
      const bY = c.height * 1.1, rows = 22, cols = 26
      for (let i=0; i<=rows; i++) {
        const t = (i + off/80) / rows, e = t*t
        const y = vp.y + (bY - vp.y)*e, sp = e*c.width*1.2
        const a = e*.08
        ctx.strokeStyle = i%4===0 ? `rgba(0,229,200,${a*.8})` : `rgba(255,255,255,${a})`
        ctx.lineWidth = .5; ctx.beginPath()
        ctx.moveTo(vp.x - sp/2, y); ctx.lineTo(vp.x + sp/2, y); ctx.stroke()
      }
      for (let j=-cols/2; j<=cols/2; j++) {
        const x = vp.x + j*(c.width/cols), a = (1-Math.abs(j)/(cols/2))*.06
        ctx.strokeStyle = `rgba(255,255,255,${a})`
        ctx.beginPath(); ctx.moveTo(vp.x, vp.y); ctx.lineTo(x, bY); ctx.stroke()
      }
      off = (off+.5)%80; requestAnimationFrame(draw)
    }
    draw()
  })()

  // Neural
  ;(function() {
    const c = document.getElementById('nc'), ctx = c.getContext('2d')
    function resize() { c.width = W(); c.height = H() }
    resize(); window.addEventListener('resize', resize)
    const nodes = Array.from({length:52}, (_,i) => ({
      x:Math.random()*W(), y:Math.random()*H(),
      vx:(Math.random()-.5)*.18, vy:(Math.random()-.5)*.18,
      r: i<8 ? 2.5+Math.random()*2 : Math.random()*1.6+.4,
      ph: Math.random()*Math.PI*2, ps:.009+Math.random()*.01,
      hub: i<8
    }))
    const sigs = []
    let frame = 0
    function draw() {
      ctx.clearRect(0,0,c.width,c.height); frame++
      if (frame%90===0) {
        const hi = Math.floor(Math.random()*8)
        nodes.slice(0, nodes.length).forEach((n,i) => {
          if (i===hi) return
          const d = Math.hypot(n.x-nodes[hi].x, n.y-nodes[hi].y)
          if (d < 180 && Math.random()>.5) sigs.push({
            x:nodes[hi].x, y:nodes[hi].y, tx:n.x, ty:n.y,
            p:0, sp:.014+Math.random()*.008, teal:Math.random()>.6
          })
        })
      }
      for (let i=0;i<nodes.length;i++) for (let j=i+1;j<nodes.length;j++) {
        const dx=nodes[i].x-nodes[j].x, dy=nodes[i].y-nodes[j].y
        const d=Math.sqrt(dx*dx+dy*dy), mx=(nodes[i].hub||nodes[j].hub)?165:105
        if (d<mx) { ctx.beginPath(); ctx.strokeStyle=`rgba(255,255,255,${(1-d/mx)*.065})`; ctx.lineWidth=.4; ctx.moveTo(nodes[i].x,nodes[i].y); ctx.lineTo(nodes[j].x,nodes[j].y); ctx.stroke() }
      }
      for (let i=sigs.length-1;i>=0;i--) {
        const s=sigs[i]; s.p+=s.sp; if(s.p>=1){sigs.splice(i,1);continue}
        const px=s.x+(s.tx-s.x)*s.p, py=s.y+(s.ty-s.y)*s.p
        const px0=s.x+(s.tx-s.x)*Math.max(0,s.p-.14), py0=s.y+(s.ty-s.y)*Math.max(0,s.p-.14)
        const col=s.teal?'0,229,200':'200,200,230'
        const g=ctx.createLinearGradient(px0,py0,px,py); g.addColorStop(0,`rgba(${col},0)`); g.addColorStop(1,`rgba(${col},.8)`)
        ctx.beginPath(); ctx.strokeStyle=g; ctx.lineWidth=1.5; ctx.moveTo(px0,py0); ctx.lineTo(px,py); ctx.stroke()
        ctx.beginPath(); ctx.arc(px,py,2.2,0,Math.PI*2); ctx.fillStyle=`rgba(${col},.9)`; ctx.fill()
      }
      nodes.forEach(n => {
        n.ph+=n.ps; const p=Math.sin(n.ph)*.5+.5
        if (n.hub) { ctx.beginPath(); ctx.arc(n.x,n.y,n.r+4+p*3,0,Math.PI*2); ctx.strokeStyle=`rgba(0,229,200,${.07+p*.1})`; ctx.lineWidth=.5; ctx.stroke() }
        ctx.beginPath(); ctx.arc(n.x,n.y,n.r+(n.hub?p*.8:0),0,Math.PI*2)
        ctx.fillStyle=`rgba(${n.hub?'0,229,200':'170,170,215'},${(n.hub?.55:.22)+p*.18})`; ctx.fill()
        n.x+=n.vx; n.y+=n.vy
        if(n.x<-20||n.x>c.width+20) n.vx*=-1
        if(n.y<-20||n.y>c.height+20) n.vy*=-1
      })
      requestAnimationFrame(draw)
    }
    draw()
  })()

  // Data streams
  ;(function() {
    const c = document.getElementById('pc'), ctx = c.getContext('2d')
    function resize() { c.width = W(); c.height = H() }
    resize(); window.addEventListener('resize', resize)
    const streams = Array.from({length:16}, () => ({
      x:Math.random()*W(), y:Math.random()*H()-H(),
      sp:.35+Math.random()*.55, a:.035+Math.random()*.045
    }))
    function draw() {
      ctx.clearRect(0,0,c.width,c.height)
      ctx.font = '10px "DM Mono",monospace'
      streams.forEach(s => {
        s.y+=s.sp; if(s.y>c.height+80){s.y=-80;s.x=Math.random()*c.width}
        for(let i=0;i<6;i++){
          const a=s.a*(1-i/6)*(i===0?2:1)
          ctx.fillStyle=i===0?`rgba(0,229,200,${Math.min(a*2,.14)})` :`rgba(155,155,200,${a})`
          ctx.fillText(i%2===0?'1':'0', s.x, s.y-i*13)
        }
      })
      requestAnimationFrame(draw)
    }
    draw()
  })()
}

